# Dungeon Crawler

class Room:
    def __init__(self, name):
        self.name = name
        self.items = []
        self.enemies = []

    def describe(self):
        print(f"You enter {self.name}")
        for item in self.items:
            print(f"  You see: {item}")

    def add_enemy(self, enemy):
        self.enemies.append(enemy)
        print(f"{enemy} lurks here")

class Player:
    def __init__(self):
        self.hp = 100
        self.inventory = []
        self.position = (0, 0)

    def take_damage(self, amount):
        self.hp -= amount
        print(f"Ouch! HP: {self.hp}")

    def heal(self, amount):
        self.hp += amount
        print(f"Healed! HP: {self.hp}")

    def pickup(self, item):
        self.inventory.append(item)
        print(f"Got {item}!")
